#include <stdio.h>
#include <string.h>
int main(){
    char s[101];
    if(scanf("%100s",s)!=1) return 0;
    int l=0, r=strlen(s)-1;
    while(l<r){
        char tmp=s[l];
        s[l]=s[r];
        s[r]=tmp;
        ++l; --r;
    }
    printf("%s\n",s);
    return 0;
}

code.C++:
#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    string s;
    if(!(cin>>s)) return 0;
    int l=0, r=(int)s.size()-1;
    while(l<r){
        swap(s[l],s[r]);
        ++l; --r;
    }
    cout<<s<<"\n";
    return 0;
}

